                    if hasattr(func, '__call__'):
                        stats[field_name] = func(items)
                    else:
                        stats[field_name] = func
            except (ValueError, TypeError):
                # Handle cases where the function can't be applied
                stats[field_name] = None

        # Store the aggregated statistics for the group
        aggregated_results[group_value] = stats

    # Convert defaultdict to regular dict for the final result
    return dict(aggregated_results)
